const val BOLT_SEGS = 14
const val MAX_BOLTS = MAX_FORKS + 1
const val VERTS_PER_BOLT = BOLT_SEGS + 1
const val STRIKE_MS = 130

private class Vec2(val x: Double, val y: Double)

/** The precomputed frame arrays the shader consumes (verts / meta). */
