}

private fun boltPoint(A: Vec2, B: Vec2, t: Double, seedOff: Double, seed: Double, jagged: Double, beat: Double): Vec2 {
    val dx = B.x - A.x
    val dy = B.y - A.y
    val len = maxOf(hypot(dx, dy), 1.0)
    val dirx = dx / len
    val diry = dy / len
    val nrmx = -diry
    val nrmy = dirx
    val n = fbm(t * 6.0 + seedOff + seed, beat * 0.5) - 0.5
    val fine = fbm(t * 22.0 + seedOff * 3.1 + seed, beat) - 0.5
    val taper = sin(t * PI)
    val off = (n * 1.6 + fine * 0.5) * jagged * len * 0.16 * taper
    return Vec2(A.x + dirx * (t * len) + nrmx * off, A.y + diry * (t * len) + nrmy * off)
}

private fun writeBolt(verts: FloatArray, b: Double, A: Vec2, B: Vec2, drawn: Double, seedOff: Double, seed: Double, jagged: Double, beat: Double): Double {
    val base = b * VERTS_PER_BOLT.toDouble()
    var last = 0
    val v0 = boltPoint(A, B, 0.0, seedOff, seed, jagged, beat)
    verts[((base + 0.0) * 2.0).toInt()] = v0.x.toFloat()
    verts[((base + 0.0) * 2.0 + 1.0).toInt()] = v0.y.toFloat()
    for (i in 1 .. BOLT_SEGS) {
        val t = i.toDouble() / BOLT_SEGS.toDouble()
        if (t - 1.0 / BOLT_SEGS.toDouble() > drawn) {
            break
        }
        val tc = minOf(t, drawn)
        val v = boltPoint(A, B, tc, seedOff, seed, jagged, beat)
        verts[((base + i.toDouble()) * 2.0).toInt()] = v.x.toFloat()
        verts[((base + i.toDouble()) * 2.0 + 1.0).toInt()] = v.y.toFloat()
        last = i
    }
    return last.toDouble()
}

fun computeLightningArrays(style: Double, thickness: Double, jagged: Double, branches: Double, boltSeed: Double, width: Double, height: Double, originX: Double, originY: Double, elapsedMs: Double, life: Double): LightningArrays {
    val verts = FloatArray(MAX_BOLTS * VERTS_PER_BOLT * 2)
    val meta = FloatArray(MAX_BOLTS * 4)
    val strike = strikeProgress(elapsedMs)
    if (strike <= 0.0) {
        return LightningArrays(verts, meta)
    }
    val seed = boltSeed
    val beat = floor((elapsedMs / 1000.0) * 12.0) * style
    val jx = (hash21x(seed * 1.7) - 0.5) * width * 0.5
    val A = Vec2(clamp(originX + jx, width * 0.12, width * 0.88), height * 1.02)
    val B = Vec2(originX, originY)
    val mainSegs = writeBolt(verts, 0.0, A, B, strike, 0.0, seed, jagged, beat)
    meta[0] = mainSegs.toFloat()
    meta[1] = thickness.toFloat()
    meta[2] = 1.0f
    meta[3] = 1.0f
    val forks = maxOf(0.0, minOf(MAX_FORKS.toDouble(), floor(branches + 0.5)))
    val dlenRaw = hypot(B.x - A.x, B.y - A.y)
    val dlen = (if (dlenRaw == 0.0) 1.0 else dlenRaw)
    val dirx = (B.x - A.x) / dlen
    val diry = (B.y - A.y) / dlen
    val nrmx = -diry
    val nrmy = dirx
    val forkFade = 0.6 + 0.4 * (1.0 - smoothstep(0.5, 1.0, life))
    for (i in 0 until forks.toInt()) {
        val b = 1 + i
        val hh = hash21(i.toDouble() * 9.7 + seed + 3.0)
        val launchT = 0.18 + hh.x * 0.62
        if (strike < launchT) {
            meta[b * 4] = 0.0f
            continue
        }
        val forkA = boltPoint(A, B, launchT, 0.0, seed, jagged, beat)
        val ang = (hh.y - 0.5) * 2.2
        val reach = (0.18 + hh.x * 0.22) * dlen
        val ex = dirx * (0.5 + hh.y) + nrmx * ang
        val ey = diry * (0.5 + hh.y) + nrmy * ang
        val forkB = Vec2(forkA.x + ex * reach, forkA.y + ey * reach)
        val forkDrawn = clamp((strike - launchT) / maxOf(1.0 - launchT, 0.05), 0.0, 1.0)
        val segs = writeBolt(verts, b.toDouble(), forkA, forkB, forkDrawn, (i * 17 + 5).toDouble(), seed, jagged, beat)
        meta[b * 4] = segs.toFloat()
        meta[b * 4 + 1] = (thickness * 0.6).toFloat()
        meta[b * 4 + 2] = forkFade.toFloat()
        meta[b * 4 + 3] = 0.0f
    }
    return LightningArrays(verts, meta)
}
